import boto3


def lambda_handler(event, context):
    s3 = boto3.resource('s3')

    bucket = 'my-aws-lambda-function'
    filename = 'somefile.png'

    fileObj = open('/tmp/'+filename) # the file must exist in your path!

    fileObject = s3.Object(bucket, filename)
    fileObject.put(Body=fileObj)